import { motion, AnimatePresence } from 'framer-motion';
import Section from './components/Section';
import ContactSection from './components/ContactSection';
import ExpertiseSection from './components/ExpertiseSection';
import Layout from './components/Layout';
import { sections, type Language } from './constants/sections';

export default function LandingPage() {
  const [activeSection, setActiveSection] = useState(0);
  const [language, setLanguage] = useState<Language>('en');
  const [hoveredNav, setHoveredNav] = useState<number | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const sectionRefs = useRef<(HTMLDivElement | null)[]>([]);

  const currentSections = sections[language];

  useEffect(() => {
    const observerOptions = {
      root: containerRef.current,
      threshold: 0.5,
    };

    const observerCallback = (entries: IntersectionObserverEntry[]) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          const index = sectionRefs.current.findIndex((ref) => ref === entry.target);
          if (index !== -1) {
            setActiveSection(index);
          }
        }
      });
    };

    const observer = new IntersectionObserver(observerCallback, observerOptions);
    sectionRefs.current.forEach((ref) => { if (ref) observer.observe(ref); });

    return () => { 
      sectionRefs.current.forEach((ref) => { if (ref) observer.unobserve(ref); });
    };
  }, [language]);

  const handleNavClick = useCallback((index: number) => {
    const target = sectionRefs.current[index];
    if (target && containerRef.current) {
      containerRef.current.scrollTo({
        top: target.offsetTop,
        behavior: 'smooth'
      });
    }
  }, []);

  const toggleLanguage = useCallback(() => {
    setLanguage(prev => prev === 'mk' ? 'en' : 'mk');
  }, []);

  const isAtTop = activeSection === 0;

  return (
    <Layout>
      <motion.header 
        initial={false}
        animate={{
          backgroundColor: isAtTop ? 'rgba(3, 3, 3, 0)' : 'rgba(3, 3, 3, 0.96)',
          backdropFilter: isAtTop ? 'blur(0px)' : 'blur(15px)',
          borderBottomColor: isAtTop ? 'rgba(255, 255, 255, 0)' : 'rgba(255, 255, 255, 0.08)',
        }}
        className="fixed top-0 left-0 right-0 z-50 px-5 py-1.5 md:px-16 md:py-3.5 flex justify-between items-center transition-all duration-500 border-b"
      >
        <div className="flex-1 flex justify-start">
          <motion.button
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
            onClick={toggleLanguage}
            className="px-2.5 py-1 text-[8px] md:text-[9px] font-black uppercase tracking-widest text-white/60 border border-white/10 rounded-full hover:text-white transition-all font-mono"
            aria-label="Toggle language"
          >
            {language === 'mk' ? 'EN' : 'MK'}
          </motion.button>
        </div>

        <motion.div 
          whileHover={{ scale: 1.01 }}
          className="flex-none text-center cursor-pointer"
          onClick={() => handleNavClick(0)}
        >
          <span className="text-sm md:text-xl font-heading font-black tracking-tighter text-white uppercase">
            M&M <span className="text-primary">Media</span>
          </span>
        </motion.div>

        <div className="flex-1 flex justify-end" />
      </motion.header>

      {/* Advanced Precision Navigation */}
      <nav className="fixed right-6 md:right-10 top-1/2 -translate-y-1/2 flex flex-col items-center gap-6 z-50">
        <div className="absolute top-0 bottom-0 w-[1px] bg-white/[0.03] -z-10" />

        {currentSections.map((section, index) => {
          const isActive = index === activeSection;
          const isHovered = hoveredNav === index;

          return (
            <div key={index} className="relative flex items-center justify-center">
              <AnimatePresence>
                {isHovered && (
                  <motion.span
                    initial={{ opacity: 0, x: -10, filter: 'blur(4px)' }}
                    animate={{ opacity: 1, x: -20, filter: 'blur(0px)' }}
                    exit={{ opacity: 0, x: -10, filter: 'blur(4px)' }}
                    className="absolute right-full mr-2 font-mono text-[5px] md:text-[6px] font-black tracking-[0.4em] text-primary uppercase whitespace-nowrap hidden md:block"
                  >
                    {section.title}
                  </motion.span>
                )}
              </AnimatePresence>

              <button
                onClick={() => handleNavClick(index)}
                onMouseEnter={() => setHoveredNav(index)}
                onMouseLeave={() => setHoveredNav(null)}
                className="relative flex items-center justify-center group"
                aria-label={`Navigate to ${section.title}`}
              >
                <div className="absolute inset-[-10px] z-20" />

                <motion.div
                  animate={{
                    height: isActive ? 24 : (isHovered ? 8 : 3),
                    width: 2,
                    backgroundColor: isActive ? '#3b82f6' : (isHovered ? 'rgba(255,255,255,0.4)' : 'rgba(255,255,255,0.15)'),
                    boxShadow: isActive ? '0 0 12px rgba(59,130,246,0.5)' : 'none',
                  }}
                  transition={{ 
                    type: "spring", 
                    stiffness: 260, 
                    damping: 20 
                  }}
                  className="rounded-full relative z-10"
                />

                {isActive && (
                  <motion.div 
                    initial={{ scale: 0.5, opacity: 0 }}
                    animate={{ scale: [1, 2, 1], opacity: [0, 0.2, 0] }}
                    transition={{ duration: 2, repeat: Infinity }}
                    className="absolute w-4 h-4 rounded-full bg-primary/30 -z-10"
                  />
                )}
              </button>
            </div>
          );
        })}
      </nav>

      <div ref={containerRef} className="snap-container no-scrollbar">
        {currentSections.map((section, index) => (
          <div 
            key={`${section.id}-${language}`} 
            ref={(el) => { sectionRefs.current[index] = el; }}
            className="snap-child"
          >
            {section.id === 'contact' ? (
              <ContactSection isActive={index === activeSection} language={language} />
            ) : section.id === 'expertise' ? (
              <ExpertiseSection {...section} isActive={index === activeSection} language={language} />
            ) : (
              <Section {...section} isActive={index === activeSection} />
            )}
          </div>
        ))}
      </div>
    </Layout>
  );
}

